  const [chartData, setChartData] = useState(generateWeeklyData());
  const [insight, setInsight] = useState<SegmentInsight | null>(null);
  const [insightLoading, setInsightLoading] = useState(false);
  const [showInsightSheet, setShowInsightSheet] = useState(false);
  const [baziReportData, setBaziReportData] = useState<BaziReport | null>(null);

  // Init
  useEffect(() => {
    const profile = storage.getProfile();
    const premium = storage.getPremium();
    const bazi = storage.getBaziReport();

    if (profile) {
      setUserProfile(profile);
      setShowSystemIntro(false);
    } else {
      setShowSystemIntro(true);
    }

    setIsPremium(premium);
    if(bazi) setBaziReportData(bazi);
  }, []);

  // Handlers
  const handleProfileSubmit = (data: UserInputProfile) => {
    setUserProfile(data);
    storage.saveProfile(data);
    setShowActivation(false);
    setShowTutorial(true);
  };

  const handleAnalyze = async () => {
    if (!userProfile) {
        setShowActivation(true);
        return;
    }
    setInsightLoading(true);
    const range = { start_date: '2024-01-01', end_date: '2024-01-07' };
    try {
        const res = await generateSegmentInsight(
            range.start_date, range.end_date, 50, 52, 
            MOCK_USER_BAZI, getMockEraMeta()
        );
        setInsight(res);
        setShowInsightSheet(true);
    } catch (e) {
        console.error(e);
    } finally {
        setInsightLoading(false);
    }
  };

  const handleRangeSelect = async (range: TimeRange, startPrice: number, endPrice: number) => {
      setInsightLoading(true);
      try {
          const res = await generateSegmentInsight(
              range.start_date, range.end_date, startPrice, endPrice, 
              MOCK_USER_BAZI, getMockEraMeta()
          );
          setInsight(res);
          setShowInsightSheet(true);
      } catch (e) {
          console.error(e);
      } finally {
          setInsightLoading(false);
      }
  };

  return (
    <div className="min-h-screen bg-[#020408] text-slate-200 font-sans overflow-x-hidden pb-20">

      {showSystemIntro && (
        <SystemActivationIntro onComplete={() => setShowSystemIntro(false)} />
      )}

      {showActivation && (
        <UserInfoForm 
            onSubmit={handleProfileSubmit} 
            onCancel={() => setShowActivation(false)} 
        />
      )}

      <MetaHeader 
        era={getMockEraMeta()}
        user={userProfile ? { ...MOCK_USER_BAZI, age: new Date().getFullYear() - new Date(userProfile.birthDate).getFullYear() } : MOCK_USER_BAZI}
        synergy={MOCK_SYNERGY}
        stage={MOCK_CURRENT_STAGE}
        onOpenSettings={() => setShowUserCenter(true)}
        isGuest={!userProfile}
      />

      <DestinyHeartbeat />

      <LifeKlineChart 
        data={viewMode === 'weekly' ? generateWeeklyData() : generateMacroData()}
        selectedRange={insight?.time_range || null}
        onSelectRange={handleRangeSelect}
        viewMode={viewMode}
        onToggleView={setViewMode}
        userName={userProfile?.name}
      />

      <ThreeRingsCompass 
        epoch={MOCK_RINGS_DATA.epoch}
        year={MOCK_RINGS_DATA.year}
        quarter={MOCK_RINGS_DATA.quarter}
      />

      <InsightCardList 
        insight={insight}
        loading={insightLoading}
        era={getMockEraMeta()}
        user={MOCK_USER_BAZI}
        isPremium={isPremium}
        onShowPaywall={() => setShowUserCenter(true)}
      />

      <InsightDock 
        insight={insight}
        onAnalyze={handleAnalyze}
        loading={insightLoading}
      />

      <SegmentInsightSheet 
        isOpen={showInsightSheet}
        onClose={() => setShowInsightSheet(false)}
        insight={insight}
        era={getMockEraMeta()}
        user={MOCK_USER_BAZI}
      />

      {userProfile && (
        <UserCenter 
            isOpen={showUserCenter}
            onClose={() => setShowUserCenter(false)}
            userProfile={userProfile}
            onLogout={() => {
                storage.clearAll();
                window.location.reload();
            }}
            isPremium={isPremium}
            onUpgradeSuccess={() => {
                setIsPremium(true);
                storage.savePremium(true);
            }}
        />
      )}

      {showTutorial && (
          <OnboardingTutorial onComplete={() => setShowTutorial(false)} />
      )}

      {/* Guest Mode Activation Button */}
      {!userProfile && !showSystemIntro && !showActivation && (
            <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[35] pointer-events-auto w-full max-w-xs px-4">
                <button 
                    onClick={() => setShowActivation(true)}
                    className="w-full group relative px-6 py-4 bg-[#0F172A]/90 backdrop-blur-xl border border-white/10 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] hover:scale-[1.02] active:scale-[0.98] transition-all overflow-hidden"
