  userName: string;
  onSnailClick: () => void;
}

const getDailyTheme = (dateStr: string, isUp: boolean) => {
  let dayNum = 1;
  try {
    if (dateStr && typeof dateStr === 'string') {
        const parsed = parseInt(dateStr.split('-').join('').slice(-2));
        if (!isNaN(parsed)) dayNum = parsed;
    }
  } catch (e) {
    dayNum = 1;
  }

  if (isUp) {
    const themes = [
      { label: 'Opportunity', desc: 'Investment/Wealth' },
      { label: 'Connection', desc: 'Social/Network' },
      { label: 'Breakthrough', desc: 'Career/Action' },
      { label: 'Creativity', desc: 'Idea/Flow' }
    ];
    return themes[dayNum % themes.length] || themes[0];
  } else {
    const themes = [
      { label: 'Health', desc: 'Rest/Recovery' },
      { label: 'Introspection', desc: 'Inner/Thought' },
      { label: 'Learning', desc: 'Skill/Study' },
      { label: 'Harmony', desc: 'Patience/Peace' }
    ];
    return themes[dayNum % themes.length] || themes[0];
  }
};

